const standings = $input.item.json.standings || [];
const today = new Date().toISOString().split('T')[0];

function abbrev(t) { return (t.teamAbbrev?.default || t.teamAbbrev || '???'); }
function name(t)   { return (t.teamCommonName?.default || t.teamName?.default || abbrev(t)); }
const byPoints = (a, b) => (b.points - a.points) || ((b.regulationWins||0) - (a.regulationWins||0));

function toTeamInfo(t, inPlayoffs) {
  return {
    abbrev: abbrev(t), name: name(t),
    division: t.divisionAbbrev || '?',
    points: t.points || 0, gp: t.gamesPlayed || 0,
    wins: t.wins || 0, losses: t.losses || 0, otLosses: t.otLosses || 0,
    row: t.regulationWins || 0, inPlayoffs: !!inPlayoffs
  };
}

// Eastern teams only
const eastern = standings.filter(t => t.conferenceAbbrev === 'E');

// Sort each division separately, then take top 3 — this is the key correctness fix
// (prevents conference-wide sort from misidentifying division leaders)
const atlantic = [...eastern.filter(t => t.divisionAbbrev === 'A')].sort(byPoints);
const metro    = [...eastern.filter(t => t.divisionAbbrev === 'M')].sort(byPoints);

const divChamps = [...atlantic.slice(0, 3), ...metro.slice(0, 3)];
const divChampSet = new Set(divChamps.map(abbrev));

// Wildcard pool: all eastern teams not in top-3 of their division, sorted by points
const wildcardPool = eastern
  .filter(t => !divChampSet.has(abbrev(t)))
  .sort(byPoints);

// NHL wildcard: top 2 = in playoffs, rest = out
const wc1      = wildcardPool[0]; // 1st wildcard (safely in)
const wc2      = wildcardPool[1]; // 2nd wildcard = LAST IN
const firstOut = wildcardPool[2]; // FIRST OUT

// Bubble display: wildcard pool top 6
const bubbleTeams = wildcardPool.slice(0, 6).map(t =>
  toTeamInfo(t, abbrev(t) === abbrev(wc1) || abbrev(t) === abbrev(wc2))
);

const teamColors = {
  BOS:'#FCB514', BUF:'#003087', DET:'#CE1126', FLA:'#C8102E',
  MTL:'#CF0A2C', OTT:'#C52032', TBL:'#002868', TOR:'#003E7E',
  CAR:'#CE1126', CBJ:'#002654', NJD:'#CE1126', NYI:'#00539B',
  NYR:'#0038A8', PHI:'#F74902', PIT:'#FCB514', WSH:'#041E42',
  VGK:'#B4975A', EDM:'#FC4C02', CGY:'#C8102E', VAN:'#00843D',
};

return [{
  json: {
    today,
    bubbleTeams,
    lastIn:   toTeamInfo(wc2, true),
    firstOut: toTeamInfo(firstOut, false),
    pointsGap: (firstOut?.points || 0) - (wc2?.points || 0),
    colors: bubbleTeams.map(t => teamColors[t.abbrev] || '#64748b'),
    divChampions: divChamps.map(t => toTeamInfo(t, true))
  }
}];

const bubble = $('Parse Bubble Data').item.json;
const scheduleInfo = $('Parse Schedule').item.json;
const charts = $input.item.json;
const d = { ...bubble, ...charts };
const { bubbleTeams, lastIn, firstOut, pointsGap, today, chartUrl, chart2Url } = d;
const scheduleText = scheduleInfo.scheduleText || 'Schedule data unavailable';
const newsContext = $input.item.json.newsContext || '';

const bubbleStr = bubbleTeams.map((t, i) =>
  `${i+1}. ${t.name} (${t.abbrev}) — ${t.points} pts, ${t.gp} GP, ROW: ${t.row}` +
  (i === 0 ? ' [WC1 IN]' : i === 1 ? ' [WC2 LAST IN]' : i === 2 ? ' [FIRST OUT]' : '')
).join('\n');

const dateFormatted = new Date(today + 'T12:00:00Z').toLocaleDateString('en-US', {
  month: 'long', day: 'numeric', year: 'numeric'
});
const gap = Math.abs(pointsGap || 0);

const systemPrompt = `You are the lead writer for The Hockey Brain (thehockeybrain.com) — a smart hockey analytics publication.

OUTPUT FORMAT — follow exactly, output ONLY the HTML below, nothing else:

<div class="article-bottom-line">
<strong>The Call</strong>
[1-2 sentences. Direct, opinionated prediction: who makes the playoffs and who doesn't. Back it with one key data point.]
</div>

<div class="article-quick-take">
<p><strong>Quick Take</strong></p>
<ul>
<li>[1-sentence fact about who currently holds the bubble lead]</li>
<li>[1-sentence: exact points for last-in vs first-out, and the gap]</li>
<li>[1-sentence: tiebreaker or schedule insight]</li>
</ul>
</div>

<div class="article-key-stat">
<span class="stat-number">[THE KEY NUMBER — e.g. 1 or 2]</span>
<span class="stat-label">[short label, e.g. "point separates the last playoff spot from elimination"]</span>
</div>

<p>[Paragraph 1: Hook — the human drama in 2-3 sentences. Name specific teams and players.]</p>

<p>[Paragraph 2: The cutoff line — exactly who is in and who is out, with point totals.]</p>

<p>[Paragraph 3: ROW tiebreaker — what happens if teams finish tied in points.]</p>

<p>[Paragraph 4: Schedule and momentum — who has the tougher road, who is playing well.]</p>

RULES:
- Use <strong>Team Name (X pts)</strong> for teams, e.g. <strong>Detroit Red Wings (84 pts)</strong>
- Each <p> is 2-3 sentences max — short, punchy
- NO markdown, NO asterisks, NO h1/h2 tags
- Start immediately with <div class="article-bottom-line"> — zero preamble
- In the Quick Take <li> bullets: do NOT wrap entire sentences in <strong>. Only bold the team name or number, not the whole sentence.`;

const userPrompt = `Write the playoff bubble article for ${dateFormatted}.

EASTERN BUBBLE DATA:
${bubbleStr}

Last team IN:   ${lastIn?.name} (${lastIn?.abbrev}) — ${lastIn?.points} pts, ${lastIn?.gp} GP, ROW: ${lastIn?.row}
First team OUT: ${firstOut?.name} (${firstOut?.abbrev}) — ${firstOut?.points} pts, ${firstOut?.gp} GP, ROW: ${firstOut?.row}
Gap: ${gap} point(s) between last-in and first-out

UPCOMING GAMES (next 7 days for bubble teams): ${scheduleText}

${newsContext ? newsContext + '\n\n' : ''}Output ONLY the HTML. Start immediately with <div class="article-bottom-line">.`;

return [{ json: { ...d, dateFormatted, systemPrompt, userPrompt } }];

const articleHtml = $input.item.json.choices?.[0]?.message?.content || '';
const d = $('Build Gemini Prompt').item.json;
const { today, chartUrl, chart2Url, bubbleTeams, lastIn, firstOut, dateFormatted } = d;

const slug        = 'eastern-playoff-bubble-' + today;
const readableDate = dateFormatted || today;
const gap         = Math.abs(d.pointsGap || 0);

const title    = 'Eastern Playoff Bubble: ' + (lastIn?.name || 'Last In') + ' vs ' + (firstOut?.name || 'First Out') + ' | ' + readableDate;
const metaTitle = 'NHL Eastern Playoff Race ' + readableDate + ' | The Hockey Brain';
const metaDesc  = (lastIn?.name || 'Last in') + ' (' + (lastIn?.points || 0) + ' pts) hold the final wildcard, ' + gap + ' point(s) ahead of ' + (firstOut?.name || 'First out') + '. Full bubble breakdown ' + readableDate + '.';
const year = (today || '2026').substring(0, 4);
const keywords = [
  'nhl playoff race', 'eastern conference standings', 'nhl bubble teams',
  (lastIn?.name || '').toLowerCase(), (firstOut?.name || '').toLowerCase(),
  'nhl wildcard race ' + year, 'hockey analytics'
].filter(Boolean);

// Chart 2 appended at the end of the article (after paragraphs)
const chart2Html = '<div class="article-chart-secondary"><img src="' + (chart2Url || '') +
  '" alt="Points vs Regulation Wins – Tiebreaker Context" /></div>';

const content = articleHtml.trim() + '\n' + chart2Html;

const safeContent = content.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${');
const postObj = '  {\n' +
  '    slug: '            + JSON.stringify(slug)         + ',\n' +
  '    title: '           + JSON.stringify(title)        + ',\n' +
  '    metaTitle: '       + JSON.stringify(metaTitle)    + ',\n' +
  '    metaDescription: ' + JSON.stringify(metaDesc)     + ',\n' +
  '    keywords: '        + JSON.stringify(keywords)     + ',\n' +
  '    publishedAt: '     + JSON.stringify(today)        + ',\n' +
  '    chartUrl: '        + JSON.stringify(chartUrl||'') + ',\n' +
  '    content: `'        + safeContent + '`,\n' +
  '  },';

return [{ json: { slug, title, metaDesc, chartUrl, chart2Url, postObj, articlePreview: content.substring(0, 600) } }];

const ghData = $input.item.json;
const postObj = $('Build Post Object').item.json.postObj;
const sha = ghData.sha;
const currentContent = Buffer.from(ghData.content, 'base64').toString('utf8');

// Insert new post at the start of the posts array (after 'posts: BlogPost[] = [')
const insertAfter = 'export const posts: BlogPost[] = [';
const insertIdx = currentContent.indexOf(insertAfter) + insertAfter.length;
const newContent = currentContent.slice(0, insertIdx) + '\n' + postObj + '\n' + currentContent.slice(insertIdx);

const newContentB64 = Buffer.from(newContent).toString('base64');

return [{
  json: {
    slug: $('Build Post Object').item.json.slug,
    title: $('Build Post Object').item.json.title,
    chartUrl: $('Build Post Object').item.json.chartUrl,
    metaDesc: $('Build Post Object').item.json.metaDesc,
    sha,
    newContentB64
  }
}];

