try { xml2 = String($('Fetch HockeyBuzz').item.json.data || $('Fetch HockeyBuzz').item.json.body || ''); } catch(e) {}

const nhlNews = parseRSS(xml1, 4);
const buzzNews = parseRSS(xml2, 3);
const allNews = [...nhlNews, ...buzzNews].slice(0, 6);

const newsContext = allNews.length > 0
  ? 'RECENT NHL NEWS (injuries/trades/lineup changes):\n' + allNews.map(h => '• ' + h).join('\n')
  : '';

const prev = $('Parse Schedule').item.json;
return { ...prev, newsContext };
